def solve(cardiac_output_ml_min, valve_type, heart_rate_bpm, flow_time_seconds, pressure_gradient_mmhg):
    # Step 1: Select the appropriate K value based on the type of valve
    # The K value is selected based on the valve type: 44.3 for aortic, pulmonary, or tricuspid valves, and 37.7 for mitral valves
    if valve_type in ['aortic', 'pulmonary', 'tricuspid']:
        k_value = 44.3
    elif valve_type == 'mitral':
        k_value = 37.7
    else:
        raise ValueError("Invalid valve type. Valid options are 'aortic', 'mitral', 'pulmonary', 'tricuspid'.")

    yield {
        "step_name": "select_k_value_based_on_valve",
        "step_description": "Select the appropriate K value based on the type of valve.",
        "step_result": k_value,
        "unit": None
    }

    # Step 2: Select the appropriate flow time based on the type of valve
    # For aortic, pulmonary, or tricuspid valves, use the systolic ejection period (SEP) in seconds. For mitral valves, use the diastolic filling period (DFP) in seconds.
    if valve_type in ['aortic', 'pulmonary', 'tricuspid']:
        flow_time = flow_time_seconds  # Use SEP as provided
    elif valve_type == 'mitral':
        flow_time = flow_time_seconds  # Use DFP as provided
    else:
        raise ValueError("Invalid valve type. Valid options are 'aortic', 'mitral', 'pulmonary', 'tricuspid'.")

    yield {
        "step_name": "select_flow_time_based_on_valve",
        "step_description": "Select the appropriate flow time based on the type of valve.",
        "step_result": flow_time,
        "unit": "seconds"
    }

    # Step 3: Calculate the valve area using the Gorlin formula
    # VA = CO / (K × HR × FT × √ΔP)
    # Convert heart rate from bpm to per minute (already in per minute)
    # Convert pressure gradient from mmHg to square root
    sqrt_pressure_gradient = math.sqrt(pressure_gradient_mmhg)

    valve_area_cm2 = cardiac_output_ml_min / (k_value * heart_rate_bpm * flow_time * sqrt_pressure_gradient)

    yield {
        "step_name": "calculate_valve_area_using_gorlin_formula",
        "step_description": "Calculate the valve area using the Gorlin formula.",
        "step_result": valve_area_cm2,
        "unit": "cm²"
    }

    return valve_area_cm2
